import{_ as a,c as i,o,ae as r}from"./chunks/framework.Bw7rlmih.js";const p=JSON.parse('{"title":"CP-005: Provider Connector Matrix","description":"","frontmatter":{},"headers":[],"relativePath":"control-plane/atomic/CP-005-provider-connector-matrix.md","filePath":"control-plane/atomic/CP-005-provider-connector-matrix.md"}'),t={name:"control-plane/atomic/CP-005-provider-connector-matrix.md"};function l(c,e,n,d,s,u){return o(),i("div",null,e[0]||(e[0]=[r('<h1 id="cp-005-provider-connector-matrix" tabindex="-1">CP-005: Provider Connector Matrix <a class="header-anchor" href="#cp-005-provider-connector-matrix" aria-label="Permalink to &quot;CP-005: Provider Connector Matrix&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Define supported remote connectors and exact feature surface for each.</p><h2 id="inputs-outputs" tabindex="-1">Inputs / Outputs <a class="header-anchor" href="#inputs-outputs" aria-label="Permalink to &quot;Inputs / Outputs&quot;">​</a></h2><ul><li>Input: provider config + scope prefix + key selectors.</li><li>Output: normalized key/value documents + source metadata.</li></ul><h2 id="public-interfaces" tabindex="-1">Public Interfaces <a class="header-anchor" href="#public-interfaces" aria-label="Permalink to &quot;Public Interfaces&quot;">​</a></h2><ul><li><code>POST /v1/connectors</code></li><li><code>GET /v1/connectors</code></li><li><code>POST /v1/connectors/{id}/test</code></li><li><code>konfigo connector add|test|list</code></li></ul><h2 id="data-contracts" tabindex="-1">Data Contracts <a class="header-anchor" href="#data-contracts" aria-label="Permalink to &quot;Data Contracts&quot;">​</a></h2><h2 id="connector-matrix-phase-targets" tabindex="-1">Connector Matrix (Phase Targets) <a class="header-anchor" href="#connector-matrix-phase-targets" aria-label="Permalink to &quot;Connector Matrix (Phase Targets)&quot;">​</a></h2><h3 id="vault" tabindex="-1">Vault <a class="header-anchor" href="#vault" aria-label="Permalink to &quot;Vault&quot;">​</a></h3><ul><li>KV v2 reads</li><li>KV v1 reads</li><li>generic logical path reads</li><li>dynamic secret engines: database/aws/gcp/azure</li><li>lease metadata capture</li><li>optional Transit decrypt reads</li></ul><h3 id="aws" tabindex="-1">AWS <a class="header-anchor" href="#aws" aria-label="Permalink to &quot;AWS&quot;">​</a></h3><ul><li>SSM Parameter Store: <code>GetParameter</code>, <code>GetParametersByPath</code></li><li>Secrets Manager reads</li><li>AppConfig reads</li><li>S3 object config reads</li><li>optional DynamoDB document source</li></ul><h3 id="gcp" tabindex="-1">GCP <a class="header-anchor" href="#gcp" aria-label="Permalink to &quot;GCP&quot;">​</a></h3><ul><li>Secret Manager reads</li><li>GCS object config reads</li><li>optional Firestore document source</li><li>optional/deprecated Runtime Config adapter</li></ul><h3 id="azure" tabindex="-1">Azure <a class="header-anchor" href="#azure" aria-label="Permalink to &quot;Azure&quot;">​</a></h3><ul><li>Key Vault Secrets reads</li><li>Azure App Configuration (keys, labels, feature flags)</li><li>Blob object config reads</li><li>optional Cosmos DB document source</li></ul><h3 id="sops" tabindex="-1">SOPS <a class="header-anchor" href="#sops" aria-label="Permalink to &quot;SOPS&quot;">​</a></h3><ul><li>Encrypted YAML/JSON/TOML/ENV files</li><li>key backends: age, PGP, AWS KMS, GCP KMS, Azure Key Vault</li><li>local and remote file source support</li></ul><h3 id="consul" tabindex="-1">Consul <a class="header-anchor" href="#consul" aria-label="Permalink to &quot;Consul&quot;">​</a></h3><ul><li>KV key reads</li><li>KV prefix reads</li><li>blocking query/watch support</li></ul><h3 id="etcd" tabindex="-1">etcd <a class="header-anchor" href="#etcd" aria-label="Permalink to &quot;etcd&quot;">​</a></h3><ul><li>v3 key reads</li><li>v3 prefix reads</li><li>watch support</li></ul><h3 id="redis" tabindex="-1">Redis <a class="header-anchor" href="#redis" aria-label="Permalink to &quot;Redis&quot;">​</a></h3><ul><li>string key reads</li><li>hash field reads</li><li>optional RedisJSON document reads</li><li>optional pub/sub invalidation hooks</li></ul><h3 id="nice-to-have-extras" tabindex="-1">Nice-to-Have Extras <a class="header-anchor" href="#nice-to-have-extras" aria-label="Permalink to &quot;Nice-to-Have Extras&quot;">​</a></h3><ul><li>Kubernetes ConfigMap/Secret source</li><li>HTTP(S) config endpoint source with ETag behavior</li><li>Git ref/file source</li></ul><h3 id="normalized-output-contract" tabindex="-1">Normalized Output Contract <a class="header-anchor" href="#normalized-output-contract" aria-label="Permalink to &quot;Normalized Output Contract&quot;">​</a></h3><p>Each fetched item must provide:</p><ul><li><code>path</code></li><li><code>value</code> (or redacted marker)</li><li><code>source.provider</code></li><li><code>source.location</code></li><li><code>source.version</code> (if available)</li><li><code>source.etag_or_revision</code> (if available)</li><li><code>source.lease</code> (if available)</li><li><code>fetchedAt</code></li></ul><h2 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h2><ul><li>Connector never returns provider-native shape to downstream pipeline.</li><li>All connectors output normalized contract.</li><li>Connector errors are typed and include provider + location.</li></ul><h2 id="failure-modes" tabindex="-1">Failure Modes <a class="header-anchor" href="#failure-modes" aria-label="Permalink to &quot;Failure Modes&quot;">​</a></h2><ul><li><code>400 invalid_connector_config</code></li><li><code>401 connector_auth_failed</code></li><li><code>404 connector_path_not_found</code></li><li><code>429 connector_rate_limited</code></li><li><code>503 connector_upstream_unavailable</code></li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance Criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance Criteria&quot;">​</a></h2><ol><li>Each listed phase-1 provider has at least one integration test.</li><li>Test endpoint validates credentials and minimal read path.</li><li>Normalized output contract matches schema for all providers.</li><li>Unsupported optional provider features return explicit capability error.</li></ol><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>Write-back to remote providers.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>CP-006 cache semantics.</li><li>CP-002 auth.</li></ul>',40)]))}const m=a(t,[["render",l]]);export{p as __pageData,m as default};
